import json
with open('baseline-packages.json') as f: b = json.load(f)
with open('after-cpm-packages.json') as f: a = json.load(f)
def pkgs(data):
    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result.setdefault(name, {})[pkg['id']] = pkg['resolvedVersion']
    return result
bp, ap = pkgs(b), pkgs(a)
match = bp == ap
print('Package versions match:', match)
if not match:
    for proj in set(list(bp.keys()) + list(ap.keys())):
        for pkg in set(list(bp.get(proj,{}).keys()) + list(ap.get(proj,{}).keys())):
            bv = bp.get(proj,{}).get(pkg)
            av = ap.get(proj,{}).get(pkg)
            if bv != av: print(f'  DIFF {proj}/{pkg}: {bv} -> {av}')
"

